INSERT INTO `admin_tickets` VALUES (33,88,'none','http://www.drawnimals.com/play.php?p=logout','Flagged Content (Other)','Clicking on the logout button does not log out the player, instead, you just go back to the play screen. I\'m not sure whether or not this applies to outside of battle or not.',0,0,NULL,0,1363456639,NULL),(34,88,'none','http://www.drawnimals.com/play.php?','Report Error (other-minor)','The feed says [username] is building there pokedex THAY just added [pokemon], should be they, not thay, and needs comma.',0,0,NULL,0,1363555184,NULL),(35,88,'none','http://www.drawnimals.com/play.php?p=explore','Report Error (other-minor)','If you start with charmander, after defeating Headmaster Torch, she tells you to go to Honeydew.',0,0,NULL,0,1363833510,NULL),(36,95,'Clhuang','http://www.drawnimals.com/play.php','Flagged Content (Other)','I am fighting a psyduck and what pops up is Notice: Undefined variable: battle in /var/www/html/pages/battle/command.php on line 33 Notice: Trying to get property of non-object in /var/www/html/pages/battle/command.php on line 33 Fatal error: Call to a member function IS_Fainted() on a non-object in /var/www/html/pages/battle/command.php on line 35',0,0,NULL,0,1364061712,NULL),(37,11,'none','http://www.drawnimals.com/play.php?','Report Error (visual)','Layers on town03/school/classroomc need to be fixed. tree is behind people.',0,0,NULL,0,1364093923,NULL),(38,103,'none','http://www.drawnimals.com/play.php?','Report Error (visual)','its stuck on the loading screen with the running fire one and won\'t do anything else',0,0,NULL,0,1364173047,NULL),(39,50,'none','http://www.drawnimals.com/play.php','Suggestion (Suggestion)','Its early in the morning...the town has no lights...can\'t see where I have been or going. Tried refresh but did not work?',0,0,NULL,0,1365836712,NULL);
