DROP TABLE IF EXISTS `explore_shop_inventory`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `explore_shop_inventory` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `shopid` varchar(60) DEFAULT '',
  `item` varchar(60) DEFAULT '',
  `price` int(10) unsigned DEFAULT '0',
  `quantity` int(10) unsigned DEFAULT '0',
  `catagory` varchar(60) DEFAULT '',
  `minimum_level` int(10) unsigned DEFAULT '0',
  `maximum_level` int(10) unsigned DEFAULT '0',
  `spawn_type` int(10) unsigned DEFAULT '0',
  `spawn_interval` int(10) unsigned DEFAULT '0',
  `spawn_last` bigint(20) unsigned NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=53 DEFAULT CHARSET=latin1;
/*!40101 SET character_set_client = @saved_cs_client */;

