--
-- Table structure for table `sys_pkmn`
--

DROP TABLE IF EXISTS `sys_pkmn`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `sys_pkmn` (
  `species` varchar(30) NOT NULL,
  `evolvecode` text,
  `catch_rate` int(11) DEFAULT NULL,
  `hp_base` int(11) DEFAULT NULL,
  `atk_base` int(11) DEFAULT NULL,
  `def_base` int(11) DEFAULT NULL,
  `sp_atk_base` int(11) DEFAULT NULL,
  `sp_def_base` int(11) DEFAULT NULL,
  `speed_base` int(11) DEFAULT NULL,
  `type0` int(11) DEFAULT NULL,
  `type1` int(11) DEFAULT NULL,
  `hp_ev` int(11) DEFAULT NULL,
  `atk_ev` int(11) DEFAULT NULL,
  `def_ev` int(11) DEFAULT NULL,
  `sp_atk_ev` int(11) DEFAULT NULL,
  `sp_def_ev` int(11) DEFAULT NULL,
  `speed_ev` int(11) DEFAULT NULL,
  `exp` int(11) DEFAULT NULL,
  `level_type` int(11) DEFAULT NULL,
  `hatch_time` int(11) DEFAULT NULL,
  `gender_rate` decimal(10,0) DEFAULT NULL,
  `info_hungerguage_base` tinyint(3) unsigned DEFAULT '128',
  `info_energyguage_base` tinyint(3) unsigned DEFAULT '128',
  `info_cleanguage_base` tinyint(3) unsigned DEFAULT '128',
  `info_evilguage_base` tinyint(3) unsigned DEFAULT '128',
  `item_carrying` text,
  `item_carrying_chance` bigint(20) unsigned DEFAULT '0',
  `description` text,
  PRIMARY KEY (`species`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;
/*!40101 SET character_set_client = @saved_cs_client */;

