DROP TABLE IF EXISTS `usr_pkmn`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `usr_pkmn` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `userid` bigint(20) unsigned DEFAULT NULL,
  `name` varchar(20) DEFAULT NULL,
  `gender` int(11) DEFAULT NULL,
  `origid` bigint(20) unsigned DEFAULT NULL,
  `origarea` varchar(30) DEFAULT NULL,
  `birthdate` bigint(20) unsigned NOT NULL,
  `species` varchar(20) DEFAULT 'bulbasaur',
  `item_holding` varchar(20) DEFAULT '',
  `level` int(11) DEFAULT NULL,
  `xp` bigint(20) unsigned DEFAULT NULL,
  `battle_active` int(11) DEFAULT '0',
  `party_active` int(11) DEFAULT '0',
  `hp` int(11) DEFAULT NULL,
  `hp_iv` int(11) DEFAULT NULL,
  `hp_ev` int(11) DEFAULT '0',
  `atk_iv` int(11) DEFAULT NULL,
  `atk_ev` int(11) DEFAULT '0',
  `atk_mod` int(11) DEFAULT '0',
  `def_iv` int(11) DEFAULT NULL,
  `def_ev` int(11) DEFAULT '0',
  `def_mod` int(11) DEFAULT '0',
  `sp_atk_iv` int(11) DEFAULT NULL,
  `sp_atk_ev` int(11) DEFAULT '0',
  `sp_atk_mod` int(11) DEFAULT '0',
  `sp_def_iv` int(11) DEFAULT NULL,
  `sp_def_ev` int(11) DEFAULT '0',
  `sp_def_mod` int(11) DEFAULT '0',
  `speed_iv` int(11) DEFAULT NULL,
  `speed_ev` int(11) DEFAULT '0',
  `speed_mod` int(11) DEFAULT '0',
  `acc` int(11) DEFAULT '0',
  `evv` int(11) DEFAULT '0',
  `ailments` mediumtext,
  `move0` varchar(20) DEFAULT '',
  `move0pp` int(11) DEFAULT NULL,
  `move0ppmax` int(11) DEFAULT NULL,
  `move1` varchar(20) DEFAULT '',
  `move1pp` int(11) DEFAULT NULL,
  `move1ppmax` int(11) DEFAULT NULL,
  `move2` varchar(20) DEFAULT '',
  `move2pp` int(11) DEFAULT NULL,
  `move2ppmax` int(11) DEFAULT NULL,
  `move3` varchar(20) DEFAULT '',
  `move3pp` int(11) DEFAULT NULL,
  `move3ppmax` int(11) DEFAULT NULL,
  `move4` varchar(20) DEFAULT '',
  `evolving` text,
  `info_aboutme` blob,
  `info_trading` tinyint(4) DEFAULT '0',
  `info_likes` tinyblob,
  `info_dislikes` tinyblob,
  `info_personality` tinyblob,
  `info_mood` tinyblob,
  `info_happyguage` smallint(6) unsigned DEFAULT '32767',
  `info_hungerguage` smallint(6) unsigned DEFAULT '32767',
  `info_energyguage` smallint(6) unsigned DEFAULT '32767',
  `info_cleanguage` smallint(6) unsigned DEFAULT '32767',
  `info_evilguage` smallint(6) unsigned DEFAULT '32767',
  `info_lastupdated` int(10) unsigned DEFAULT '0',
  UNIQUE KEY `id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=270 DEFAULT CHARSET=latin1;
